import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Check, ChevronRight, Wand2, Loader2, Sparkles } from 'lucide-react';
import { EventType, VibeType, MoodboardResult } from '../types';

const Wizard: React.FC = () => {
  const [step, setStep] = useState(1);
  const [eventType, setEventType] = useState<EventType>(null);
  const [vibe, setVibe] = useState<VibeType>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<MoodboardResult | null>(null);

  const handleStartAnalysis = () => {
    setIsAnalyzing(true);
    setTimeout(() => {
      let finalResult: MoodboardResult;

      if (eventType === 'Casamento') {
        if (vibe === 'Clássico') {
          finalResult = {
            title: 'Elegância Atemporal',
            description: 'Seu casamento será marcado por colunas de flores brancas, árvores de cerejeira branca e iluminação âmbar suave. O luxo clássico em cada pétala.',
            image: 'https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=1200'
          };
        } else if (vibe === 'Boho') {
          finalResult = {
            title: 'Refúgio Orgânico',
            description: 'Pampas grass, flores secas misturadas a flores nobres e árvores rústicas com luzes de fada. Um cenário romântico, fluido e inesquecível.',
            image: 'https://images.unsplash.com/photo-1515934751635-c81c6bc9a2d8?auto=format&fit=crop&q=80&w=1200'
          };
        } else {
          finalResult = {
            title: 'Design Contemporâneo',
            description: 'Estruturas geométricas, orquídeas exóticas e árvores minimalistas com neon. Para quem busca um evento que é uma obra de arte moderna.',
            image: 'https://images.unsplash.com/photo-1478146059778-26028b07395a?auto=format&fit=crop&q=80&w=1200'
          };
        }
      } else {
        // 15 Anos
        if (vibe === 'Clássico') {
          finalResult = {
            title: 'Baile de Debutante Real',
            description: 'Um palácio de flores em tons de rosa seco e dourado. Árvores de LED e arranjos imersivos que transformam o salão em um conto de fadas.',
            image: 'https://images.unsplash.com/photo-1511795409834-ef04bbd61622?auto=format&fit=crop&q=80&w=1200'
          };
        } else if (vibe === 'Boho') {
          finalResult = {
            title: 'Jardim Encantado',
            description: 'Muitas folhagens, árvores de macramê e flores silvestres. Uma vibe Coachella de luxo, jovem e vibrante.',
            image: 'https://images.unsplash.com/photo-1522673607200-164883eecd4c?auto=format&fit=crop&q=80&w=1200'
          };
        } else {
          finalResult = {
            title: 'Cyber Glamour',
            description: 'Cenários espelhados, árvores metálicas com flores holográficas e muita tecnologia. O futuro da celebração.',
            image: 'https://images.unsplash.com/photo-1464366400600-7168b8af9bc3?auto=format&fit=crop&q=80&w=1200'
          };
        }
      }

      setResult(finalResult);
      setIsAnalyzing(false);
      setStep(4);
    }, 2500);
  };

  const reset = () => {
    setStep(1);
    setEventType(null);
    setVibe(null);
    setResult(null);
  };

  return (
    <section id="wizard" className="py-24 bg-white relative overflow-hidden">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <motion.h2 
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            className="text-3xl md:text-5xl font-serif text-[#1A3C34] mb-4"
          >
            Descubra Sua Identidade Visual
          </motion.h2>
          <p className="text-[#1A3C34]/60 max-w-xl mx-auto">
            Nossa Inteligência de Design analisa suas preferências para criar um moodboard exclusivo para o seu grande dia.
          </p>
        </div>

        <div className="max-w-4xl mx-auto">
          {/* Progress Bar */}
          <div className="flex justify-between mb-12 relative">
            <div className="absolute top-1/2 left-0 w-full h-[1px] bg-[#E6C6C6] -translate-y-1/2 z-0" />
            {[1, 2, 3].map((num) => (
              <div 
                key={num}
                className={`relative z-10 w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-500 ${step >= num ? 'bg-[#D4AF37] border-[#D4AF37] text-white' : 'bg-white border-[#E6C6C6] text-[#E6C6C6]'}`}
              >
                {step > num ? <Check size={18} /> : num}
              </div>
            ))}
          </div>

          {/* Steps */}
          <div className="min-h-[400px]">
            <AnimatePresence mode="wait">
              {step === 1 && (
                <motion.div
                  key="step1"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="grid md:grid-cols-2 gap-8"
                >
                  <button 
                    onClick={() => { setEventType('Casamento'); setStep(2); }}
                    className="group relative h-80 overflow-hidden border border-[#E6C6C6] hover:border-[#D4AF37] transition-all"
                  >
                    <img src="https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=800" className="absolute inset-0 w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-60 group-hover:opacity-100" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
                    <div className="absolute bottom-8 left-8 text-left">
                      <h3 className="text-white text-2xl font-serif mb-2">Casamento</h3>
                      <p className="text-white/70 text-sm">A união eterna em cenários majestosos</p>
                    </div>
                  </button>
                  <button 
                    onClick={() => { setEventType('15 Anos'); setStep(2); }}
                    className="group relative h-80 overflow-hidden border border-[#E6C6C6] hover:border-[#D4AF37] transition-all"
                  >
                    <img src="https://images.unsplash.com/photo-1464366400600-7168b8af9bc3?auto=format&fit=crop&q=80&w=800" className="absolute inset-0 w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-60 group-hover:opacity-100" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
                    <div className="absolute bottom-8 left-8 text-left">
                      <h3 className="text-white text-2xl font-serif mb-2">15 Anos</h3>
                      <p className="text-white/70 text-sm">A celebração da vida e novos começos</p>
                    </div>
                  </button>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div
                  key="step2"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="grid md:grid-cols-3 gap-6"
                >
                  {['Clássico', 'Boho', 'Moderno'].map((v) => (
                    <button 
                      key={v}
                      onClick={() => { setVibe(v as VibeType); setStep(3); }}
                      className="p-12 border border-[#E6C6C6] hover:bg-[#1A3C34] hover:text-white transition-all text-center group"
                    >
                      <h3 className="text-xl font-serif mb-4 group-hover:text-[#D4AF37]">{v}</h3>
                      <p className="text-xs uppercase tracking-widest opacity-60">Escolher Vibe</p>
                    </button>
                  ))}
                </motion.div>
              )}

              {step === 3 && (
                <motion.div
                  key="step3"
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  className="text-center py-12"
                >
                  <div className="mb-8">
                    <Wand2 size={64} className="mx-auto text-[#D4AF37] mb-4" />
                    <h3 className="text-2xl font-serif text-[#1A3C34]">Tudo Pronto!</h3>
                    <p className="text-[#1A3C34]/60 mt-2">Clique abaixo para que nossa IA de design crie seu moodboard personalizado.</p>
                  </div>
                  <button 
                    onClick={handleStartAnalysis}
                    disabled={isAnalyzing}
                    className="bg-[#1A3C34] text-white px-12 py-5 uppercase tracking-[0.2em] text-sm flex items-center justify-center gap-3 mx-auto hover:bg-[#D4AF37] transition-all"
                  >
                    {isAnalyzing ? (
                      <>
                        <Loader2 className="animate-spin" size={20} />
                        Analisando Perfil...
                      </>
                    ) : (
                      <>
                        Gerar Moodboard
                        <ChevronRight size={18} />
                      </>
                    )}
                  </button>
                </motion.div>
              )}

              {step === 4 && result && (
                <motion.div
                  key="step4"
                  initial={{ opacity: 0, y: 30 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="bg-[#FAF9F6] p-8 md:p-12 shadow-2xl relative border border-[#D4AF37]/20"
                >
                  <div className="grid md:grid-cols-2 gap-12 items-center">
                    <div>
                      <div className="inline-flex items-center gap-2 text-[#D4AF37] uppercase tracking-[0.3em] text-xs font-bold mb-4">
                        <Sparkles size={14} />
                        Seu Estilo Ideal
                      </div>
                      <h3 className="text-3xl md:text-4xl font-serif text-[#1A3C34] mb-6">{result.title}</h3>
                      <p className="text-[#1A3C34]/70 leading-relaxed mb-8">
                        {result.description}
                      </p>
                      <div className="space-y-4">
                        <div className="flex items-center gap-3 text-sm font-medium">
                          <Check size={16} className="text-[#D4AF37]" />
                          Árvores Gigantes Customizadas
                        </div>
                        <div className="flex items-center gap-3 text-sm font-medium">
                          <Check size={16} className="text-[#D4AF37]" />
                          Design de Mesa Posta Exclusiva
                        </div>
                        <div className="flex items-center gap-3 text-sm font-medium">
                          <Check size={16} className="text-[#D4AF37]" />
                          Curadoria de Flores Nobres
                        </div>
                      </div>
                      <div className="mt-10 flex gap-4">
                        <button className="bg-[#D4AF37] text-white px-8 py-4 text-xs uppercase tracking-widest hover:bg-[#1A3C34] transition-all">
                          Salvar Moodboard
                        </button>
                        <button onClick={reset} className="text-[#1A3C34] border-b border-[#1A3C34] text-xs uppercase tracking-widest hover:text-[#D4AF37] hover:border-[#D4AF37] transition-all">
                          Refazer Teste
                        </button>
                      </div>
                    </div>
                    <div className="relative aspect-[3/4] overflow-hidden">
                      <img src={result.image} alt={result.title} className="w-full h-full object-cover" />
                      <div className="absolute inset-0 border-[15px] border-white/20 m-4 pointer-events-none" />
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Wizard;

import React from 'react';
import { motion } from 'framer-motion';
