import React from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Wizard from './components/Wizard';
import Gallery from './components/Gallery';
import Footer from './components/Footer';
import { motion, useScroll, useSpring } from 'framer-motion';

const App: React.FC = () => {
  const { scrollYProgress } = useScroll();
  const scaleX = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  return (
    <div className="relative min-h-screen bg-[#FAF9F6]">
      {/* Scroll Progress Bar */}
      <motion.div 
        className="fixed top-0 left-0 right-0 h-1 bg-[#D4AF37] z-[60] origin-left"
        style={{ scaleX }}
      />

      <Navbar />

      <main>
        <Hero />

        {/* Intro Text Section */}
        <section className="py-24 bg-[#1A3C34] text-white">
          <div className="container mx-auto px-6 max-w-4xl text-center">
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
            >
              <h3 className="text-2xl md:text-3xl font-serif mb-8 text-[#E6C6C6]">
                "Decoração não é sobre o que você vê, mas sobre como você se sente ao entrar no ambiente."
              </h3>
