import { Sparkles, Wand2, Loader2, Heart, Star, Flower2, Moon, Sun } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

// Data for the wizard steps
const WIZARD_DATA = {
  events: [
    { id: 'wedding', label: 'Casamento', icon: Heart, img: 'https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=400' },
    { id: 'debutante', label: '15 Anos', icon: Star, img: 'https://images.unsplash.com/photo-1464366400600-7168b8af9bc3?auto=format&fit=crop&q=80&w=400' },
  ],
  vibes: [
    { id: 'classic', label: 'Clássico', icon: Flower2, description: 'Elegância atemporal e sofisticação tradicional.' },
    { id: 'boho', label: 'Boho Chic', icon: Sun, description: 'Natural, rústico e cheio de texturas orgânicas.' },
    { id: 'modern', label: 'Moderno', icon: Moon, description: 'Minimalismo, luxo contemporâneo e linhas limpas.' },
  ]
};

/**
 * Wizard component for personalized style discovery using Gemini API.
 * This fixes the "no default export" error in App.tsx and completes the truncated file.
 */
const Wizard: React.FC = () => {
  const [step, setStep] = useState(1);
  const [selections, setSelections] = useState({
    event: '',
    vibe: '',
    preferences: ''
  });
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{ title: string; description: string; colors: string[] } | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      // Use the injected API_KEY from environment
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Como um designer de interiores de luxo especializado em eventos monumentais para a marca D'FLORES, crie um conceito de decoração exclusivo. 
      Evento: ${selections.event}
      Vibe: ${selections.vibe}
      Preferências adicionais: ${selections.preferences}

      Retorne um JSON com: "title" (um nome impactante para o conceito), "description" (uma descrição poética e detalhada focada em árvores gigantes e arranjos monumentais) e "colors" (uma lista de 3 cores hexadecimais que compõem a paleta).`;

      // gemini-3-flash-preview is ideal for this creative reasoning task
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              colors: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["title", "description", "colors"]
          }
        }
      });

      // Safely access .text property from GenerateContentResponse
      const jsonStr = response.text?.trim();
      if (jsonStr) {
        const data = JSON.parse(jsonStr);
        setResult(data);
        setStep(4);
      }
    } catch (error) {
      console.error("Error generating concept:", error);
    } finally {
      setLoading(false);
    }
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  return (
    <section id="wizard" className="py-24 bg-white">
      <div className="container mx-auto px-6 max-w-4xl">
        <div className="text-center mb-12">
          <span className="text-[#D4AF37] uppercase tracking-[0.3em] text-[10px] font-bold">Experiência Personalizada</span>
          <h2 className="text-4xl font-serif text-[#1A3C34] mt-2 italic">Simulador de Cenários</h2>
        </div>

        <div className="bg-[#FAF9F6] p-8 md:p-16 shadow-sm border border-[#1A3C34]/5 min-h-[500px] flex flex-col justify-center">
          <AnimatePresence mode="wait">
            {step === 1 && (
              <motion.div
                key="step1"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-8"
              >
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center mb-8">Qual momento vamos celebrar?</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {WIZARD_DATA.events.map(event => (
                    <button
                      key={event.id}
                      onClick={() => { setSelections({ ...selections, event: event.label }); nextStep(); }}
                      className="relative group h-48 overflow-hidden"
                    >
                      <img src={event.img} alt={event.label} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                      <div className="absolute inset-0 bg-[#1A3C34]/40 group-hover:bg-[#1A3C34]/60 transition-colors flex flex-col items-center justify-center text-white">
