const WIZARD_DATA = {
  events: [
    { id: 'wedding', label: 'Casamento', icon: Heart, img: 'https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=600' },
    { id: 'debutante', label: '15 Anos', icon: Star, img: 'https://images.unsplash.com/photo-1464366400600-7168b8af9bc3?auto=format&fit=crop&q=80&w=600' },
  ],
  vibes: [
    { id: 'classic', label: 'Clássico', icon: Flower2, description: 'Elegância atemporal e sofisticação tradicional.' },
    { id: 'boho', label: 'Boho Chic', icon: Sun, description: 'Natural, rústico e cheio de texturas orgânicas.' },
    { id: 'modern', label: 'Moderno', icon: Moon, description: 'Minimalismo, luxo contemporâneo e linhas limpas.' },
  ]
};

const Wizard: React.FC = () => {
  const [step, setStep] = useState(1);
  const [selections, setSelections] = useState({
    event: '',
    vibe: '',
    preferences: ''
  });
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{ title: string; description: string; colors: string[] } | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Como um designer de luxo, crie um conceito exclusivo para um evento de ${selections.event} com vibe ${selections.vibe}. Preferências: ${selections.preferences}. 
      O foco deve ser o uso de árvores decorativas gigantes e arranjos imersivos. 
      Retorne JSON: { "title": "...", "description": "...", "colors": ["#...", "#...", "#..."] }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["title", "description", "colors"]
          }
        }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setStep(4);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const contactConsultant = () => {
    const message = `Olá! Usei o simulador D'Flores e amei o conceito "${result?.title}". Gostaria de um orçamento! Evento: ${selections.event}. Vibe: ${selections.vibe}.`;
    window.open(`https://wa.me/5521987654321?text=${encodeURIComponent(message)}`, '_blank');
  };

  return (
    <section id="wizard" className="py-24 bg-[#FAF9F6] border-y border-[#1A3C34]/5">
      <div className="container mx-auto px-6 max-w-5xl">
