          <p className="mt-4 text-[#1A3C34]/60 font-light max-w-xl mx-auto">Responda 3 perguntas e nossa inteligência de design criará uma proposta visual exclusiva para o seu orçamento.</p>
        </div>

        <div className="bg-white p-8 md:p-16 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#D4AF37] to-[#1A3C34]" />

          <AnimatePresence mode="wait">
            {step === 1 && (
              <motion.div key="s1" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Qual o motivo da celebração?</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {WIZARD_DATA.events.map(ev => (
                    <button key={ev.id} onClick={() => { setSelections({ ...selections, event: ev.label }); setStep(2); }} className="relative group h-64 overflow-hidden shadow-lg transition-transform hover:-translate-y-2">
                      <img src={ev.img} className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt={ev.label} />
                      <div className="absolute inset-0 bg-[#1A3C34]/40 group-hover:bg-[#1A3C34]/60 transition-colors flex flex-col items-center justify-center text-white">
                        <ev.icon size={40} className="mb-4 text-[#D4AF37]" />
                        <span className="text-lg uppercase tracking-[0.3em] font-bold">{ev.label}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            {step === 2 && (
              <motion.div key="s2" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Qual estilo faz seu coração bater mais forte?</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {WIZARD_DATA.vibes.map(v => (
                    <button key={v.id} onClick={() => { setSelections({ ...selections, vibe: v.label }); setStep(3); }} className="p-10 border border-[#1A3C34]/10 hover:border-[#D4AF37] hover:bg-[#FAF9F6] transition-all flex flex-col items-center text-center">
                      <v.icon size={32} className="text-[#D4AF37] mb-6" />
                      <span className="text-sm uppercase tracking-widest font-bold mb-4">{v.label}</span>
                      <p className="text-[10px] uppercase tracking-tighter text-[#1A3C34]/50 leading-relaxed">{v.description}</p>
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            {step === 3 && (
              <motion.div key="s3" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Algum detalhe inegociável?</h3>
                <textarea 
                  className="w-full h-40 p-8 bg-[#FAF9F6] border border-[#1A3C34]/10 focus:outline-none focus:border-[#D4AF37] font-light italic"
                  placeholder="Ex: Árvores de cerejeira na entrada, paleta em tons de Marsala..."
                  value={selections.preferences}
                  onChange={(e) => setSelections({...selections, preferences: e.target.value})}
                />
                <div className="flex justify-center">
                  <button 
                    disabled={loading}
                    onClick={handleGenerate}
