                    {loading ? <Loader2 className="animate-spin" size={18} /> : <Wand2 size={18} />}
                    Gerar Proposta de Cenário
                  </button>
                </div>
              </motion.div>
            )}

            {step === 4 && result && (
              <motion.div key="s4" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="grid md:grid-cols-2 gap-12 items-center">
                <div className="space-y-8">
                  <div className="inline-flex items-center gap-2 text-[#D4AF37] uppercase tracking-widest text-[10px] font-bold">
                    <Sparkles size={14} /> Conceito Exclusivo
                  </div>
                  <h3 className="text-4xl font-serif text-[#1A3C34] italic">{result.title}</h3>
                  <p className="text-sm font-light leading-loose text-[#1A3C34]/70">{result.description}</p>
                  <div className="flex gap-4">
                    {result.colors.map(c => (
                      <div key={c} className="w-10 h-10 rounded-full border border-black/5" style={{ backgroundColor: c }} />
                    ))}
                  </div>
                </div>
                <div className="bg-[#1A3C34] p-10 text-white space-y-8 shadow-inner">
                  <h4 className="text-xs uppercase tracking-[0.3em] font-bold text-[#D4AF37]">Gostou da proposta?</h4>
                  <p className="text-xs font-light opacity-70">Este é apenas o começo. Nossos designers monumentais podem transformar essa ideia em um cenário real para o seu grande dia.</p>
                  <button onClick={contactConsultant} className="w-full bg-[#D4AF37] text-white py-5 text-xs uppercase tracking-[0.3em] font-bold flex items-center justify-center gap-3 hover:bg-white hover:text-[#1A3C34] transition-all">
                    <MessageCircle size={18} />
                    Falar com Consultor
                  </button>
                  <button onClick={() => setStep(1)} className="w-full border border-white/20 py-4 text-[10px] uppercase tracking-widest hover:border-white transition-all opacity-50 hover:opacity-100">
                    Refazer Simulação
                  </button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </section>
  );
