  const handleGenerate = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Você é o Designer Chefe de Eventos da D'Flores Decorações, especialista em ultra-luxo e árvores gigantes.
      Crie um conceito de decoração monumental para um(a) ${selections.event} no estilo ${selections.vibe}.
