      2. Use um tom poético e sofisticado. 
      3. Mencione obrigatoriamente a presença de Árvores Gigantes e curadoria floral exclusiva.
      4. Retorne apenas o JSON no formato:
      {
        "title": "Título Impactante em PT-BR",
        "description": "Descrição envolvente em PT-BR sobre o cenário imersivo.",
        "colors": ["#hex1", "#hex2", "#hex3"]
      }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["title", "description", "colors"]
          }
        }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
