import { Sparkles, Wand2, Loader2, Heart, Star, Flower2, Moon, Sun, MessageCircle, Image as ImageIcon } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

const WIZARD_DATA = {
  events: [
    { id: 'wedding', label: 'Casamento', icon: Heart, img: 'https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=600' },
    { id: 'debutante', label: '15 Anos', icon: Star, img: 'https://images.unsplash.com/photo-1464366400600-7168b8af9bc3?auto=format&fit=crop&q=80&w=600' },
  ],
  vibes: [
    { id: 'classic', label: 'Clássico', icon: Flower2, description: 'Elegância atemporal e sofisticação tradicional.' },
    { id: 'boho', label: 'Boho Chic', icon: Sun, description: 'Natural, rústico e cheio de texturas orgânicas.' },
    { id: 'modern', label: 'Moderno', icon: Moon, description: 'Minimalismo, luxo contemporâneo e linhas limpas.' },
  ]
};

const Wizard: React.FC = () => {
  const [step, setStep] = useState(1);
  const [selections, setSelections] = useState({
    event: '',
    vibe: '',
    preferences: ''
  });
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{ title: string; description: string; colors: string[]; imageUrl?: string } | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // 1. Gerar Texto do Conceito
      const textPrompt = `Você é o Designer Chefe de Eventos da D'Flores Decorações, especialista em ultra-luxo.
      Crie um conceito de decoração monumental para um(a) ${selections.event} no estilo ${selections.vibe}.
      Desejos do cliente: "${selections.preferences}".
      RESPONDA EM PORTUGUÊS DO BRASIL. Fale sobre árvores gigantes e curadoria floral.
      Formato JSON: { "title": "string", "description": "string", "colors": ["string"] }`;

      const textResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textPrompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["title", "description", "colors"]
          }
        }
      });

      const conceptData = JSON.parse(textResponse.text || '{}');

      // 2. Gerar Imagem Exemplo do Cenário
      const imagePrompt = `A ultra-luxurious event decoration for a ${selections.event} in ${selections.vibe} style. 
      Featuring massive decorative trees, exquisite flowers, and ambient lighting. 
      Concept: ${conceptData.title}. High-end photography, cinematic lighting, architectural digest style.`;

      const imageResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{ text: imagePrompt }],
        config: {
          imageConfig: {
            aspectRatio: "16:9"
          }
        }
      });

      let imageUrl = '';
      for (const part of imageResponse.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }

      setResult({ ...conceptData, imageUrl });
      setStep(4);
    } catch (error) {
      console.error("Erro na geração:", error);
    } finally {
      setLoading(false);
    }
  };

  const contactConsultant = () => {
    const message = `Olá! Realizei a simulação D'Flores para meu evento de ${selections.event} e adorei o conceito "${result?.title}". Gostaria de um orçamento!`;
    window.open(`https://wa.me/5521987654321?text=${encodeURIComponent(message)}`, '_blank');
  };

  return (
    <section id="wizard" className="py-24 bg-[#FAF9F6] border-y border-[#1A3C34]/5">
      <div className="container mx-auto px-6 max-w-6xl">
        <div className="text-center mb-16">
          <span className="text-[#D4AF37] uppercase tracking-[0.4em] text-[10px] font-bold block mb-4">Ateliê Criativo Digital</span>
          <h2 className="text-4xl md:text-5xl font-serif text-[#1A3C34] italic">Simule seu Cenário</h2>
          <p className="mt-4 text-[#1A3C34]/60 font-light max-w-xl mx-auto italic">Deixe nossa inteligência criativa visualizar o esboço do seu próximo grande momento.</p>
        </div>

        <div className="bg-white shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#D4AF37] to-[#1A3C34]" />

          <AnimatePresence mode="wait">
            {step === 1 && (
              <motion.div key="s1" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="p-8 md:p-16 space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Qual o motivo da celebração?</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {WIZARD_DATA.events.map(ev => (
                    <button key={ev.id} onClick={() => { setSelections({ ...selections, event: ev.label }); setStep(2); }} className="relative group h-64 overflow-hidden shadow-lg transition-transform hover:-translate-y-2">
                      <img src={ev.img} className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt={ev.label} />
                      <div className="absolute inset-0 bg-[#1A3C34]/40 group-hover:bg-[#1A3C34]/60 transition-colors flex flex-col items-center justify-center text-white">
                        <ev.icon size={40} className="mb-4 text-[#D4AF37]" />
                        <span className="text-lg uppercase tracking-[0.3em] font-bold">{ev.label}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            {step === 2 && (
              <motion.div key="s2" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="p-8 md:p-16 space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Qual estilo traduz seu sonho?</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {WIZARD_DATA.vibes.map(v => (
                    <button key={v.id} onClick={() => { setSelections({ ...selections, vibe: v.label }); setStep(3); }} className="p-10 border border-[#1A3C34]/10 hover:border-[#D4AF37] hover:bg-[#FAF9F6] transition-all flex flex-col items-center text-center group">
                      <v.icon size={32} className="text-[#D4AF37] mb-6 transition-transform group-hover:scale-110" />
                      <span className="text-sm uppercase tracking-widest font-bold mb-4">{v.label}</span>
                      <p className="text-[10px] uppercase tracking-tighter text-[#1A3C34]/50 leading-relaxed">{v.description}</p>
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            {step === 3 && (
              <motion.div key="s3" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="p-8 md:p-16 space-y-10">
                <h3 className="text-2xl font-serif text-[#1A3C34] text-center italic">Algum detalhe inegociável?</h3>
                <textarea 
                  className="w-full h-40 p-8 bg-[#FAF9F6] border border-[#1A3C34]/10 focus:outline-none focus:border-[#D4AF37] font-light italic"
                  placeholder="Ex: Árvores de cerejeira na entrada, paleta em tons de Marsala, arranjos suspensos..."
                  value={selections.preferences}
                  onChange={(e) => setSelections({...selections, preferences: e.target.value})}
                />
                <div className="flex justify-center">
                  <button 
                    disabled={loading}
                    onClick={handleGenerate}
                    className="bg-[#1A3C34] text-white px-16 py-5 text-xs uppercase tracking-[0.4em] font-bold flex items-center gap-4 hover:bg-[#D4AF37] transition-all shadow-xl disabled:opacity-50"
                  >
                    {loading ? <Loader2 className="animate-spin" size={18} /> : <Wand2 size={18} />}
                    Visualizar Cenário Exclusivo
                  </button>
                </div>
              </motion.div>
            )}

            {step === 4 && result && (
              <motion.div key="s4" initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} className="flex flex-col">
                <div className="relative w-full aspect-video bg-[#1A3C34]/5 overflow-hidden">
                  {result.imageUrl ? (
                    <img src={result.imageUrl} className="w-full h-full object-cover" alt="Cenário Gerado" />
                  ) : (
                    <div className="w-full h-full flex flex-col items-center justify-center text-[#1A3C34]/20">
                      <ImageIcon size={64} strokeWidth={1} />
                      <p className="mt-4 text-[10px] uppercase tracking-widest">Visualização indisponível</p>
                    </div>
                  )}
                  <div className="absolute inset-0 bg-gradient-to-t from-[#1A3C34] via-transparent to-transparent opacity-60" />
                  <div className="absolute bottom-8 left-8 right-8 text-white">
                    <div className="inline-flex items-center gap-2 text-[#D4AF37] uppercase tracking-widest text-[9px] font-bold mb-2">
                      <Sparkles size={12} /> Exclusividade D'Flores
                    </div>
                    <h3 className="text-3xl md:text-5xl font-serif italic">{result.title}</h3>
                  </div>
                </div>

                <div className="p-8 md:p-12 grid md:grid-cols-3 gap-12">
                  <div className="md:col-span-2 space-y-6">
                    <p className="text-sm font-light leading-loose text-[#1A3C34]/70">{result.description}</p>
                    <div className="flex gap-4">
                      {result.colors.map(c => (
                        <div key={c} className="w-8 h-8 rounded-full border border-black/5 shadow-sm" style={{ backgroundColor: c }} />
                      ))}
                    </div>
                  </div>
                  <div className="bg-[#FAF9F6] p-8 border-l-4 border-[#D4AF37] flex flex-col justify-center">
                    <h4 className="text-[10px] uppercase tracking-[0.3em] font-bold text-[#1A3C34] mb-4">Transforme este conceito em realidade</h4>
                    <button onClick={contactConsultant} className="w-full bg-[#1A3C34] text-white py-4 text-[10px] uppercase tracking-[0.3em] font-bold flex items-center justify-center gap-3 hover:bg-[#D4AF37] transition-all shadow-lg mb-4">
                      <MessageCircle size={16} />
                      Solicitar este Cenário
                    </button>
                    <button onClick={() => setStep(1)} className="text-[9px] uppercase tracking-widest text-[#1A3C34]/40 hover:text-[#1A3C34] transition-colors">
                      Gerar Nova Inspiração
                    </button>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </section>
  );
};

export default Wizard;

