const VirtualConcierge: React.FC = () => {
  const [stage, setStage] = useState<'hidden' | 'typing' | 'active' | 'minimized'>('hidden');

  useEffect(() => {
    // Start sequence after 1 second
    const startTimer = setTimeout(() => {
      setStage('typing');
    }, 1000);

    // Switch from typing to active after 2 more seconds
    const typeTimer = setTimeout(() => {
      setStage((prev) => (prev === 'typing' ? 'active' : prev));
    }, 3000);

    return () => {
      clearTimeout(startTimer);
      clearTimeout(typeTimer);
    };
  }, []);

  const handleClose = (e: React.MouseEvent) => {
    e.stopPropagation();
    setStage('minimized');
  };

  const handleOpenChat = () => {
    window.open("https://wa.me/5521987654321?text=Olá! Gostaria de ajuda para realizar minha festa dos sonhos.", "_blank");
    setStage('minimized');
  };

  const handleRestore = () => {
    if (stage === 'minimized') {
      setStage('active');
    } else {
      handleOpenChat();
    }
  };

  return (
    <div className="fixed bottom-24 right-6 md:right-10 z-[90] flex flex-col items-end pointer-events-none">
      <AnimatePresence>
        {stage === 'active' && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.9 }}
