        )}
      </AnimatePresence>

      <div className="pointer-events-auto cursor-pointer" onClick={handleRestore}>
        <div className="relative group">
           {/* Typing Indicator */}
          <AnimatePresence>
            {stage === 'typing' && (
              <motion.div
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0 }}
                className="absolute bottom-full right-0 mb-3 bg-white px-4 py-2 rounded-2xl rounded-br-none shadow-xl border border-[#1A3C34]/5"
              >
                <div className="flex gap-1">
