                      </button>
                    );
                  })}
                </div>
              </motion.div>
            )}

            {step === 3 && (
              <motion.div 
                key="s3" 
                variants={stepVariants}
                initial="initial"
                animate="animate"
                exit="exit"
                transition={transitionProps}
                className="p-8 md:p-16 flex-1 flex flex-col justify-center items-center"
