const App: React.FC = () => {
  const { scrollYProgress } = useScroll();
  const scaleX = useSpring(scrollYProgress, { stiffness: 100, damping: 30 });
  const atelierRef = useRef<HTMLElement>(null);

  // Parallax for Atelier section
  const { scrollYProgress: atelierProgress } = useScroll({
    target: atelierRef,
    offset: ["start end", "end start"]
  });

  const atelierY = useTransform(atelierProgress, [0, 1], [50, -50]);
  const atelierImageY = useTransform(atelierProgress, [0, 1], [100, -100]);

  useEffect(() => {
    // Inicialização do Lenis
    // wrapper: window garante que ele controle o scroll da página inteira
    const lenis = new Lenis({
      wrapper: window,
      content: document.documentElement,
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      orientation: 'vertical',
      gestureOrientation: 'vertical',
      smoothWheel: true,
      touchMultiplier: 2,
    });

    let rafId: number;

    function raf(time: number) {
      lenis.raf(time);
      rafId = requestAnimationFrame(raf);
    }

    rafId = requestAnimationFrame(raf);

    // Garante que o layout seja recalculado se a janela mudar de tamanho
    const handleResize = () => lenis.resize();
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(rafId);
      lenis.destroy();
    };
  }, []);

