                  className="mt-12 w-full bg-[#1A3C34] text-white py-5 text-[10px] uppercase tracking-[0.3em] font-bold hover:bg-[#D4AF37] transition-all shadow-xl"
                >
                  Desejo algo semelhante
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
};

