            Carregar Mais Inspirações
          </button>
        </motion.div>
      </div>

      {/* Gallery Modal Overlay */}
      <AnimatePresence>
        {selectedItem && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
